package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mockStatic;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

public class JavaVersionTest {

  private static MockedStatic<System> systemMock;

  @BeforeAll
  static void setUp() {
    systemMock = mockStatic(System.class);
  }

  @AfterAll
  static void tearDown() {
    systemMock.close();
  }

  @Test
  void testDetermineMajorJavaVersion_Java8() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("1.8.0_271");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int result = (int) method.invoke(null);

    assertEquals(8, result);
  }

  @Test
  void testDetermineMajorJavaVersion_Java11() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("11.0.9");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int result = (int) method.invoke(null);

    assertEquals(11, result);
  }

  @Test
  void testDetermineMajorJavaVersion_Java9_Early() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("9");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int result = (int) method.invoke(null);

    assertEquals(9, result);
  }

  @Test
  void testDetermineMajorJavaVersion_Java17_EarlyAccess() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("17-ea");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int result = (int) method.invoke(null);

    assertEquals(17, result);
  }

  @Test
  void testDetermineMajorJavaVersion_Java10_WithPatch() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    systemMock.when(() -> System.getProperty("java.version")).thenReturn("10.0.2");

    Method method = JavaVersion.class.getDeclaredMethod("determineMajorJavaVersion");
    method.setAccessible(true);
    int result = (int) method.invoke(null);

    assertEquals(10, result);
  }
}
